/**
 * 章节分析面板
 * 提供：自动摘要、人物出场统计、对话分析、情节点提取
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  message,
  Spin,
  Tabs,
  Statistic,
  Row,
  Col,
  Tag,
  List,
  Progress,
  Alert,
  Divider,
} from 'antd'
import {
  FileTextOutlined,
  TeamOutlined,
  MessageOutlined,
  ThunderboltOutlined,
  ReloadOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'

interface AnalysisPanelProps {
  chapterContent: string
  chapterPath: string | null
  projectRoot: string | null
}

interface CharacterAppearance {
  name: string
  count: number
  paragraphs: number
}

interface DialogueInfo {
  speaker: string
  content: string
  position: number
}

interface PlotPoint {
  order: number
  event: string
  description: string
}

const AnalysisPanel: React.FC<AnalysisPanelProps> = ({
  chapterContent,
  chapterPath,
  projectRoot,
}) => {
  const [analyzing, setAnalyzing] = useState(false)
  const [activeTab, setActiveTab] = useState<string>('summary')

  // 摘要
  const [summary, setSummary] = useState('')
  const [summaryLoading, setSummaryLoading] = useState(false)

  // 人物统计
  const [characters, setCharacters] = useState<CharacterAppearance[]>([])
  const [dialogues, setDialogues] = useState<DialogueInfo[]>([])
  const [dialogueRatio, setDialogueRatio] = useState(0)
  const [characterStatsLoading, setCharacterStatsLoading] = useState(false)

  // 情节点
  const [plotPoints, setPlotPoints] = useState<PlotPoint[]>([])
  const [plotPointsLoading, setPlotPointsLoading] = useState(false)

  // 生成自动摘要
  const handleGenerateSummary = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setSummaryLoading(true)
    try {
      const fullPrompt = `请为以下小说章节生成200字左右的摘要，概括核心情节、人物关系变化和关键事件：

${chapterContent.slice(0, 3000)}

摘要（200字左右）：` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是一个小说摘要专家。请用简洁精炼的语言概括章节核心内容。',
      })

      if (result.success && result.content) {
        setSummary(result.content)
        setActiveTab('summary')
      } else {
        message.error(result.error || '摘要生成失败')
      }
    } catch (error) {
      message.error('摘要生成失败')
      console.error('摘要生成失败:', error)
    } finally {
      setSummaryLoading(false)
    }
  }

  // 人物出场统计
  const handleCharacterStats = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }
    setCharacterStatsLoading(true)
    try {
      // 读取角色列表
      let characterNames: string[] = []
      const charactersDir = `${projectRoot}/characters`
      const charsExistsResult = await window.electronAPI.exists(charactersDir)
      if (!charsExistsResult.success || !charsExistsResult.exists) {
        setCharacters([])
        setCharacterStatsLoading(false)
        return
      }
      const entriesResult = await window.electronAPI.readdir(charactersDir)
      if (!entriesResult.success) { console.error('读取characters目录失败:', entriesResult.error); setCharacters([]); setCharacterStatsLoading(false); return; }
      const entries = entriesResult.data || []
      const yamlFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )
      for (const file of yamlFiles) {
        const result = await window.electronAPI.yaml.read(`${charactersDir}/${file.name}`)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          if (data.name && typeof data.name === 'string') {
            characterNames.push(data.name)
          }
        }
      }

      // 统计章节中出现的人物
      const content = chapterContent
      const charAppearances: Record<string, { count: number; paragraphs: Set<number> }> = {}

      // 按段落分割
      const paragraphs = content.split(/\n\n+/)

      paragraphs.forEach((para, paraIdx) => {
        for (const name of characterNames) {
          if (para.includes(name)) {
            if (!charAppearances[name]) {
              charAppearances[name] = { count: 0, paragraphs: new Set() }
            }
            charAppearances[name].count++
            charAppearances[name].paragraphs.add(paraIdx)
          }
        }
      })

      const sortedChars = Object.entries(charAppearances)
        .map(([name, stats]) => ({
          name,
          count: stats.count,
          paragraphs: stats.paragraphs.size,
        }))
        .sort((a, b) => b.count - a.count)

      setCharacters(sortedChars)

      // 提取对话
      const dialogueRegex = /[""''『』]([^""''『』]+)[""''『』]/g
      const extractedDialogues: DialogueInfo[] = []
      let match
      let pos = 0
      while ((match = dialogueRegex.exec(content)) !== null) {
        extractedDialogues.push({
          speaker: '',
          content: match[1],
          position: match.index,
        })
        pos++
        if (pos > 50) break
      }

      // 尝试识别说话者（简化版：找引号前的名字）
      const speakerRegex = /([A-Za-z\u4e00-\u9fa5]{2,4})[""'']/
      for (const d of extractedDialogues) {
        const beforeContent = content.slice(Math.max(0, d.position - 30), d.position)
        const speakerMatch = beforeContent.match(speakerRegex)
        if (speakerMatch) {
          d.speaker = speakerMatch[1]
        }
      }

      setDialogues(extractedDialogues.slice(0, 20))

      // 计算对话占比
      const totalChars = content.replace(/\s/g, '').length
      const dialogueChars = extractedDialogues.reduce((sum, d) => sum + d.content.length, 0)
      setDialogueRatio(totalChars > 0 ? (dialogueChars / totalChars) * 100 : 0)

      setActiveTab('characters')
    } catch (error) {
      message.error('统计分析失败')
    } finally {
      setCharacterStatsLoading(false)
    }
  }

  // 情节点提取
  const handlePlotPoints = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setPlotPointsLoading(true)
    try {
      const fullPrompt = `请分析以下小说章节，提取3-5个关键情节点，按时间顺序列出：

${chapterContent.slice(0, 3000)}

情节点列表（格式）：
1. [事件名称] - 简要描述
2. [事件名称] - 简要描述
...` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是小说情节分析专家。请按时间顺序列出章节的关键事件。',
      })

      if (result.success && result.content) {
        // 解析情节点
        const lines = result.content.split('\n').filter(l => l.trim())
        const points: PlotPoint[] = []
        let order = 1
        for (const line of lines) {
          const match = line.match(/^\d+[.、]\s*(\[.+?\])?\s*(.+)/)
          if (match) {
            points.push({
              order: order++,
              event: match[1] || `情节点${order - 1}`,
              description: match[2].trim(),
            })
          }
        }
        if (points.length === 0) {
          points.push({ order: 1, event: '主要情节点', description: result.content })
        }
        setPlotPoints(points)
        setActiveTab('plotpoints')
      } else {
        message.error(result.error || '情节点提取失败')
      }
    } catch (error) {
      message.error('情节点提取失败')
    } finally {
      setPlotPointsLoading(false)
    }
  }

  // 快速分析（一次性生成所有）
  const handleFullAnalysis = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setAnalyzing(true)
    try {
      await handleGenerateSummary()
      await handleCharacterStats()
      await handlePlotPoints()
    } catch (error) {
      console.error('全量分析失败:', error)
    } finally {
      setAnalyzing(false)
    }
  }

  if (!chapterContent) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先选择章节
      </div>
    )
  }

  const totalChars = chapterContent.replace(/\s/g, '').length
  const wordCount = chapterContent.length

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>📊 章节分析</span>
        </div>

        {/* 基础统计 */}
        <Row gutter={8} style={{ marginBottom: 10 }}>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字数</span>}
              value={wordCount}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字符</span>}
              value={totalChars}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>对话占比</span>}
              value={dialogueRatio.toFixed(1)}
              suffix="%"
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
        </Row>

        {/* 分析按钮 */}
        <Space wrap style={{ marginBottom: 8 }}>
          <Button
            size="small"
            icon={<FileTextOutlined />}
            onClick={handleGenerateSummary}
            loading={summaryLoading}
          >
            生成摘要
          </Button>
          <Button
            size="small"
            icon={<TeamOutlined />}
            onClick={handleCharacterStats}
            loading={characterStatsLoading}
          >
            人物统计
          </Button>
          <Button
            size="small"
            icon={<ThunderboltOutlined />}
            onClick={handlePlotPoints}
            loading={plotPointsLoading}
          >
            情节点
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleFullAnalysis}
            loading={analyzing}
          >
            全部分析
          </Button>
        </Space>
      </div>

      {/* 分析结果 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          size="small"
          items={[
            {
              key: 'summary',
              label: <span>📝 摘要</span>,
              children: (
                <div>
                  {summaryLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="生成摘要中..." />
                    </div>
                  ) : summary ? (
                    <Card size="small" style={{ whiteSpace: 'pre-wrap' }}>
                      {summary}
                    </Card>
                  ) : (
                    <Alert
                      message="点击「生成摘要」获取本章200字摘要"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'characters',
              label: <span>👥 人物</span>,
              children: (
                <div>
                  {characterStatsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="分析人物中..." />
                    </div>
                  ) : (
                    <>
                      {/* 人物出场 */}
                      {characters.length > 0 ? (
                        <Card
                          size="small"
                          title="人物出场统计"
                          style={{ marginBottom: 12 }}
                        >
                          <List
                            size="small"
                            dataSource={characters.slice(0, 10)}
                            renderItem={(char) => (
                              <List.Item>
                                <div style={{ display: 'flex', justifyContent: 'space-between', width: '100%', alignItems: 'center' }}>
                                  <Tag color="blue">{char.name}</Tag>
                                  <Space size="small">
                                    <span style={{ fontSize: 11, color: '#999' }}>
                                      提及 {char.count} 次 · {char.paragraphs} 段
                                    </span>
                                    <Progress
                                      percent={Math.round((char.count / characters[0].count) * 100)}
                                      size="small"
                                      style={{ width: 60 }}
                                    />
                                  </Space>
                                </div>
                              </List.Item>
                            )}
                          />
                        </Card>
                      ) : (
                        <Alert
                          message="点击「人物统计」分析本章出场人物"
                          type="info"
                          showIcon
                        />
                      )}

                      {/* 对话分析 */}
                      {dialogues.length > 0 && (
                        <Card size="small" title="对话片段">
                          <List
                            size="small"
                            dataSource={dialogues.slice(0, 8)}
                            renderItem={(d) => (
                              <List.Item>
                                <div style={{ width: '100%' }}>
                                  {d.speaker && <Tag color="green" style={{ marginBottom: 4 }}>{d.speaker}</Tag>}
                                  <div style={{ fontSize: 12, fontStyle: 'italic', color: '#666' }}>
                                    「{d.content.slice(0, 60)}{d.content.length > 60 ? '...' : ''}」
                                  </div>
                                </div>
                              </List.Item>
                            )}
                          />
                          <Divider style={{ margin: '8px 0' }} />
                          <div style={{ fontSize: 11, color: '#999' }}>
                            共 {dialogues.length} 段对话，对话占比 {dialogueRatio.toFixed(1)}%
                          </div>
                        </Card>
                      )}
                    </>
                  )}
                </div>
              ),
            },
            {
              key: 'plotpoints',
              label: <span>⚡ 情节点</span>,
              children: (
                <div>
                  {plotPointsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="提取情节点中..." />
                    </div>
                  ) : plotPoints.length > 0 ? (
                    <Card size="small" title="本章关键情节点">
                      <List
                        size="small"
                        dataSource={plotPoints}
                        renderItem={(point) => (
                          <List.Item>
                            <List.Item.Meta
                              avatar={<div style={{
                                width: 24,
                                height: 24,
                                borderRadius: '50%',
                                background: '#1890ff',
                                color: '#fff',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: 12,
                              }}>
                                {point.order}
                              </div>}
                              title={<span>{point.event}</span>}
                              description={<span style={{ fontSize: 12, color: '#666' }}>{point.description}</span>}
                            />
                          </List.Item>
                        )}
                      />
                    </Card>
                  ) : (
                    <Alert
                      message="点击「情节点」提取本章关键事件"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
          ]}
        />
      </div>
    </div>
  )
}

